WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET')
ALLOWED_PARTNERS = set(os.environ.get('ALLOWED_PARTNERS', '').split(','))

def verify_signature(request, secret):
    """Verify webhook signature"""
    signature = request.headers.get('X-Signature')
    if not signature:
        return False
    
    # Get the raw body
    body = request.get_data()
    
    # Calculate expected signature
    expected_signature = hmac.new(
        secret.encode('utf-8'),
        body,
        hashlib.sha256
    ).hexdigest()
    
    # Compare signatures securely
    return hmac.compare_digest(signature, expected_signature)

def validate_partner(partner_id):
    """Validate partner is allowed"""
    if not ALLOWED_PARTNERS or '*' in ALLOWED_PARTNERS:
        return True
    return partner_id in ALLOWED_PARTNERS

def validate_request(request):
    """Validate webhook request"""
    # Check if request has required headers
    if not request.headers.get('Content-Type') == 'application/json':
        return False, "Invalid content type"
    
    # Verify signature
    if not verify_signature(request, WEBHOOK_SECRET):
        return False, "Invalid signature"
    
    # Parse JSON
    try:
        data = request.get_json()
        if not data:
            return False, "Invalid JSON"
    except Exception:
        return False, "Failed to parse JSON"
    
    # Validate partner
    partner_id = data.get('partner_id')
    if not partner_id:
        return False, "Missing partner_id"
    
    if not validate_partner(partner_id):
        return False, "Unauthorized partner"
    
    return True, "Valid"

